-- calc_events_shift_count
-- Field: Events.ShiftCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_events_shift_count(p_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM shifts WHERE event = (SELECT NULLIF(event_id, '') FROM events WHERE event_id = p_event_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_events_total_slots_needed
-- Field: Events.TotalSlotsNeeded
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_events_total_slots_needed(p_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((needed_count)::numeric), 0) FROM shifts WHERE event = p_event_id))::integer;
$$ LANGUAGE sql STABLE;

-- calc_events_total_slots_filled
-- Field: Events.TotalSlotsFilled
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_events_total_slots_filled(p_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((calc_shifts_filled_count(shift_id))::numeric), 0) FROM shifts WHERE event = p_event_id))::integer;
$$ LANGUAGE sql STABLE;

-- calc_events_coverage_percent
-- Field: Events.CoveragePercent
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_events_coverage_percent(p_event_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (calc_events_total_slots_needed(p_event_id))::NUMERIC > 0 THEN ((COALESCE(CASE WHEN (calc_events_total_slots_filled(p_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_events_total_slots_filled(p_event_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_events_total_slots_needed(p_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_events_total_slots_needed(p_event_id))::numeric ELSE NULL END, 0), 0)))::text ELSE (0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_events_staffing_grade
-- Field: Events.StaffingGrade
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_events_staffing_grade(p_event_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_events_coverage_percent(p_event_id))::NUMERIC >= 0.95 THEN ('A')::text ELSE (CASE WHEN (calc_events_coverage_percent(p_event_id))::NUMERIC >= 0.85 THEN ('B')::text ELSE (CASE WHEN (calc_events_coverage_percent(p_event_id))::NUMERIC >= 0.70 THEN ('C')::text ELSE (CASE WHEN (calc_events_coverage_percent(p_event_id))::NUMERIC >= 0.50 THEN ('D')::text ELSE ('F')::text END)::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_volunteers_name
-- Field: Volunteers.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_volunteers_name(p_volunteer_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(first_name, '') FROM volunteers WHERE volunteer_id = p_volunteer_id), ' ', (SELECT NULLIF(last_name, '') FROM volunteers WHERE volunteer_id = p_volunteer_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_volunteers_assignment_count
-- Field: Volunteers.AssignmentCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_volunteers_assignment_count(p_volunteer_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM assignments WHERE volunteer = (SELECT NULLIF(volunteer_id, '') FROM volunteers WHERE volunteer_id = p_volunteer_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_volunteers_assigned_hours
-- Field: Volunteers.AssignedHours
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_volunteers_assigned_hours(p_volunteer_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_assignments_shift_duration_hours(assignment_id))::numeric), 0) FROM assignments WHERE volunteer = p_volunteer_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_volunteers_load_status
-- Field: Volunteers.LoadStatus
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_volunteers_load_status(p_volunteer_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN ((SELECT max_hours FROM volunteers WHERE volunteer_id = p_volunteer_id))::NUMERIC > 0 THEN (CASE WHEN calc_volunteers_assigned_hours(p_volunteer_id) > (SELECT max_hours FROM volunteers WHERE volunteer_id = p_volunteer_id) THEN ('over')::text ELSE (CASE WHEN calc_volunteers_assigned_hours(p_volunteer_id) < (COALESCE(CASE WHEN ((SELECT max_hours FROM volunteers WHERE volunteer_id = p_volunteer_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT max_hours FROM volunteers WHERE volunteer_id = p_volunteer_id))::numeric ELSE NULL END, 0) * COALESCE(0.5, 0)) THEN ('under')::text ELSE ('ok')::text END)::text END)::text ELSE ('under')::text END)::text;
$$ LANGUAGE sql STABLE;

