-- calc_shifts_filled_count
-- Field: Shifts.FilledCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_shifts_filled_count(p_shift_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM assignments WHERE shift = (SELECT NULLIF(shift_id, '') FROM shifts WHERE shift_id = p_shift_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_shifts_coverage_status
-- Field: Shifts.CoverageStatus
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_shifts_coverage_status(p_shift_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_shifts_filled_count(p_shift_id) < (SELECT needed_count FROM shifts WHERE shift_id = p_shift_id) THEN ('understaffed')::text ELSE (CASE WHEN calc_shifts_filled_count(p_shift_id) > (SELECT needed_count FROM shifts WHERE shift_id = p_shift_id) THEN ('overstaffed')::text ELSE ('covered')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

